    user=os.environ["DB_USER"],
    password=os.environ["DB_PASS"],
    dbname=os.environ["DB_DATABASE"],
)

SESSION_IDS = [
    "3d1a75fa-a4be-4bc9-864f-9b7534a45020",
    "87b6b001-9a9a-42bd-b869-441a522c14a7",
    "25c8381c-9db0-4ed0-90f5-32855604fdcd",
    "2f44c5ca-78d6-4459-ad52-9a902a0b1256",
]

def walk(obj):
    if isinstance(obj, dict):
        for k, v in obj.items():
            yield k, v
            yield from ((f"{k}.{sk}", sv) for sk, sv in walk(v))
    elif isinstance(obj, list):
        for i, v in enumerate(obj):
            yield f"[{i}]", v
            yield from ((f"[{i}].{sk}", sv) for sk, sv in walk(v))

def extract_tool_calls(run):
    found = []
    for path, val in walk(run):
        if not isinstance(val, dict):
            continue
        name = val.get("name") or (val.get("function") or {}).get("name")
        if name in {
            "render_reimagine_proposals_card",
            "update_workflow_state",
            "create_or_update_file",
            "create_branch",
            "push_files",
            "run_discovery",
            "get_file_contents",
        }:
            args = val.get("arguments") or (val.get("function") or {}).get("arguments")
            found.append((name, args, path))
    return found

with conn.cursor() as cur:
    for sid in SESSION_IDS:
        cur.execute(
            "SELECT session_id, updated_at, runs FROM ai.agno_sessions WHERE session_id = %s",
            (sid,),
        )
        row = cur.fetchone()
        if not row:
            continue
        sid, updated_at, runs = row
        print(f"\n{'='*80}\nSESSION {sid} updated={updated_at} runs={len(runs or [])}")
        for i, run in enumerate(runs or []):
            blob = json.dumps(run).lower()
            if "reimaginer" not in blob:
                continue
            agent_id = run.get("agent_id") or (run.get("agent") or {}).get("id")
            member_id = run.get("member_id")
            print(f"\n--- run[{i}] agent_id={agent_id} member_id={member_id} ---")
            tools = extract_tool_calls(run)
            if tools:
                for name, args, path in tools:
                    print(f"  TOOL {name} @ {path}: {str(args)[:1000]}")
            else:
                print("  (no tracked tool calls found in run blob)")

            # system messages
            for path, val in walk(run):
                if isinstance(val, dict) and val.get("role") == "system":
                    content = val.get("content", "")
                    if isinstance(content, list):
                        content = "\n".join(str(x.get("text", x)) if isinstance(x, dict) else str(x) for x in content)
                    text = str(content)
                    if len(text) > 100 and ("reimagin" in text.lower() or "workflow state" in text.lower()):
                        print(f"  SYSTEM @ {path} ({len(text)} chars), snippet:")
                        print(text[:1500])
                        print("  ...")

            urls = sorted({p.strip('",\'') for _, v in walk(run) if isinstance(v, str) and "github.com" in v for p in v.split() if "github.com" in p})
            if urls:
                print("  github.com strings:")
                for u in urls[:15]:
                    print(f"    {u[:200]}")

conn.close()
