def get_runs(session_id):
    out = subprocess.check_output([
        'docker', 'exec', 'agentos-db', 'psql', '-U', 'ai', '-d', 'ai', '-t', '-A', '-c',
        f"SELECT runs::text FROM ai.agno_sessions WHERE session_id = '{session_id}';"
    ], text=True)
    return json.loads(out)

for sid in ['3d1a75fa-a4be-4bc9-864f-9b7534a45020','87b6b001-9a9a-42bd-b869-441a522c14a7','478b7a22-3fcd-422f-b506-5bc29e4f4b73']:
    runs = get_runs(sid)
    reimag = [(i,r) for i,r in enumerate(runs) if r.get('agent_id')=='reimaginer-agent' or 'render_reimagine_proposals_card' in json.dumps(r)]
    print(f"\nSESSION {sid}: {len(reimag)} relevant runs")
    for i,r in reimag:
        s = json.dumps(r)
        rid = r.get('run_id')
        aid = r.get('agent_id')
        tools = sorted(set(re.findall(r'"name"\s*:\s*"(render_reimagine_proposals_card|update_workflow_state|create_or_update_file|create_branch|push_files|run_discovery)"', s)))
        print(f"  run[{i}] id={rid} agent={aid} tools={tools}")
